import React, { useState, useEffect } from 'react';

const n = (v: any) => { const num = parseFloat(v); return isNaN(num) ? 0 : num; };
const fmtNum = (v: number) => v.toFixed(2).replace(/\.00$/, '');
const dias = [8, 10, 12, 14, 16, 18, 20];
const barsPerTon: Record<number, number> = { 8: 200, 10: 135, 12: 90, 14: 68, 16: 52, 18: 41, 20: 33 };
const toTons = (bars: number, d: number) => bars / (barsPerTon[d] || 100);
const STORAGE_KEY = 'tank_data_v2';

const defaultData = {
  length: '4', width: '3', height: '2.5',
    floorThick: '25', wallThick: '20', roofThick: '20',
      floorLongCount: '5', floorLongDia: 16, floorLongLayers: '2',
        floorCrossCount: '5', floorCrossDia: 16, floorCrossLayers: '2',
          wallVCount: '5', wallVDia: 14, wallVLayers: '2',
            wallHCount: '5', wallHDia: 14, wallHLayers: '2',
              roofLongCount: '5', roofLongDia: 12, roofLongLayers: '1',
                roofCrossCount: '5', roofCrossDia: 12, roofCrossLayers: '1',
                };

                const emptyData = {
                  length: '', width: '', height: '',
                    floorThick: '', wallThick: '', roofThick: '',
                      floorLongCount: '', floorLongDia: 16, floorLongLayers: '1',
                        floorCrossCount: '', floorCrossDia: 16, floorCrossLayers: '1',
                          wallVCount: '', wallVDia: 14, wallVLayers: '1',
                            wallHCount: '', wallHDia: 14, wallHLayers: '1',
                              roofLongCount: '', roofLongDia: 12, roofLongLayers: '1',
                                roofCrossCount: '', roofCrossDia: 12, roofCrossLayers: '1',
                                };

                                const Tank: React.FC = () => {
                                  const [data, setData] = useState<any>(() => {
                                      try { const stored = localStorage.getItem(STORAGE_KEY); return stored ? JSON.parse(stored) : { ...defaultData }; }
                                          catch { return { ...defaultData }; }
                                            });

                                              const update = (k: string, v: string | number) => setData((prev: any) => ({ ...prev, [k]: v }));
                                                useEffect(() => { localStorage.setItem(STORAGE_KEY, JSON.stringify(data)); }, [data]);
                                                  const reset = () => setData({ ...emptyData });
                                                    const calculate = () => { localStorage.setItem(STORAGE_KEY, JSON.stringify(data)); };

                                                      const l = n(data.length), w = n(data.width), h = n(data.height);
                                                        const ft = n(data.floorThick) / 100, wt = n(data.wallThick) / 100, rt = n(data.roofThick) / 100;
                                                          const capacity = l * w * h;
                                                            const floorConcrete = l * w * ft;
                                                              const wallConcrete = 2 * (l + w) * h * wt;
                                                                const roofConcrete = l * w * rt;
                                                                  const totalConcrete = floorConcrete + wallConcrete + roofConcrete;
                                                                    const wallArea = 2 * (l + w) * h;
                                                                      const calcBars = (len: number) => Math.ceil(len / 12);

                                                                        const items = [
                                                                            { label: 'أرضية - طولي', d: data.floorLongDia, bars: calcBars(l * n(data.floorLongCount) * w * n(data.floorLongLayers)) },
                                                                                { label: 'أرضية - عرضي', d: data.floorCrossDia, bars: calcBars(w * n(data.floorCrossCount) * l * n(data.floorCrossLayers)) },
                                                                                    { label: 'جدران - رأسي', d: data.wallVDia, bars: calcBars(wallArea * n(data.wallVCount) * n(data.wallVLayers)) },
                                                                                        { label: 'جدران - أفقي', d: data.wallHDia, bars: calcBars(wallArea * n(data.wallHCount) * n(data.wallHLayers)) },
                                                                                            { label: 'سقف - طولي', d: data.roofLongDia, bars: calcBars(l * n(data.roofLongCount) * w * n(data.roofLongLayers)) },
                                                                                                { label: 'سقف - عرضي', d: data.roofCrossDia, bars: calcBars(w * n(data.roofCrossCount) * l * n(data.roofCrossLayers)) },
                                                                                                  ].filter(item => item.bars > 0);

                                                                                                    const totalSteelTon = items.reduce((s, i) => s + toTons(i.bars, i.d), 0);const [open, setOpen] = useState(true);
                                         // حفظ النتائج للملخص
                                         const summaryByDia: Record<number, number> = {};
                                         items.forEach(item => { summaryByDia[item.d] = (summaryByDia[item.d] || 0) + item.bars; });
                                         localStorage.setItem('tank_results', JSON.stringify({
                                           concrete: totalConcrete,
                                             steel: summaryByDia,
                                               totalSteelTons: totalSteelTon
                                               }));                                                           const toggle = () => setOpen(!open);

                                                                                                    const goNext = (id?: string) => {
                                                                                                      if (!id) return;
                                                                                                        setTimeout(() => {
                                                                                                            const el = document.getElementById(id) as HTMLInputElement | null;
                                                                                                                el?.focus();
                                                                                                                    el?.select();
                                                                                                                      }, 50);
                                                                                                                      };

                                                                                                                      const SectionTitle = ({ children }: any) => (
                                                                                                                        <div style={{ position: 'relative', padding: '8px 12px', marginBottom: '12px', marginTop: '8px', background: 'linear-gradient(to left, transparent, #e8f0fe 30%)', borderRight: '4px solid #2563eb', borderRadius: '0 8px 8px 0', boxShadow: '0 0 8px rgba(37,99,235,0.1)' }}>
                                                                                                                            <span style={{ fontSize: '0.8rem', fontWeight: 800, color: '#003366' }}>{children}</span>
                                                                                                                              </div>
                                                                                                                              );

                                                                                                                              // مكون Num محسّن: غير متحكم به، يحفظ القيمة عند الخروج فقط
                                                                                                                              const Num = ({ id, go, label, value, set, unit }: any) => {
                                                                                                                                const inputRef = React.useRef<HTMLInputElement>(null);
                                                                                                                                  useEffect(() => {
                                                                                                                                      if (inputRef.current) inputRef.current.value = value;
                                                                                                                                        }, []); // مزامنة أولية فقط

                                                                                                                                          const save = () => {
                                                                                                                                              if (inputRef.current) set(inputRef.current.value);
                                                                                                                                                };

                                                                                                                                                  return (
                                                                                                                                                      <div style={{ background: '#fdfdfd', border: '1px solid #ddd', borderRadius: '8px', padding: '8px 5px', textAlign: 'center' }}>
                                                                                                                                                            <label style={{ fontSize: '0.6rem', color: '#003366', display: 'block', marginBottom: '2px', fontWeight: 700 }}>{label}</label>
                                                                                                                                                                  <input
                                                                                                                                                                          id={id} type="text" inputMode="decimal" autoComplete="off"
                                                                                                                                                                                  enterKeyHint={go ? 'next' : 'done'}
                                                                                                                                                                                          ref={inputRef} defaultValue={value}
                                                                                                                                                                                                  onBlur={save}
                                                                                                                                                                                                          onFocus={e => e.target.select()}
                                                                                                                                                                                                                  onKeyDown={e => { if (e.key === 'Enter') { e.preventDefault(); save(); goNext(go); } }}
                                                                                                                                                                                                                          style={{ width: '100%', border: 'none', textAlign: 'center', fontSize: '0.85rem', padding: '2px 0', outline: 'none', background: 'transparent', fontWeight: 700, fontFamily: 'Cairo, sans-serif' }}
                                                                                                                                                                                                                                />
                                                                                                                                                                                                                                      {unit && <span style={{ fontSize: '0.55rem', color: '#888', display: 'block', marginTop: '2px' }}>{unit}</span>}
                                                                                                                                                                                                                                          </div>
                                                                                                                                                                                                                                            );
                                                                                                                                                                                                                                            };

                                                                                                                                                                                                                                            // مكون SteelRow محسّن – حقل العدد غير متحكم به
                                                                                                                                                                                                                                            const SteelRow = ({ id, go, label, count, dia, layers, onCount, onDia, onLayers }: any) => {
                                                                                                                                                                                                                                              const inputRef = React.useRef<HTMLInputElement>(null);
                                                                                                                                                                                                                                                useEffect(() => {
                                                                                                                                                                                                                                                    if (inputRef.current) inputRef.current.value = count;
                                                                                                                                                                                                                                                      }, []);

                                                                                                                                                                                                                                                        const saveCount = () => {
                                                                                                                                                                                                                                                            if (inputRef.current) onCount(inputRef.current.value);
                                                                                                                                                                                                                                                              };

                                                                                                                                                                                                                                                                return (
                                                                                                                                                                                                                                                                    <div style={{ border: '1px solid #ddd', borderRadius: '8px', padding: '8px', marginBottom: '8px' }}>
                                                                                                                                                                                                                                                                          <div style={{ fontSize: '0.7rem', fontWeight: 700, color: '#003366', marginBottom: '4px' }}>{label}</div>
                                                                                                                                                                                                                                                                                <div style={{ display: 'flex', gap: '6px', alignItems: 'center' }}>
                                                                                                                                                                                                                                                                                        <input id={id} type="text" inputMode="decimal" autoComplete="off" enterKeyHint="next" ref={inputRef} defaultValue={count} onBlur={saveCount} onFocus={e => e.target.select()} onKeyDown={e => { if (e.key === 'Enter') { e.preventDefault(); saveCount(); goNext(go); } }} style={{ flex: 1, border: '1px solid #ccc', borderRadius: '5px', padding: '4px', fontSize: '0.8rem', textAlign: 'center', fontFamily: 'Cairo, sans-serif', fontWeight: 700 }} placeholder="عدد/م" />
                                                                                                                                                                                                                                                                                                <select style={{ width: '65px', border: '1px solid #ccc', borderRadius: '5px', padding: '4px', fontSize: '0.8rem', textAlign: 'center', fontFamily: 'Cairo, sans-serif', background: 'white', fontWeight: 700 }} value={dia} onChange={e => onDia(Number(e.target.value))}>{dias.map(d => <option key={d} value={d}>{d} مم</option>)}</select>
                                                                                                                                                                                                                                                                                                        <select style={{ width: '65px', border: '1px solid #ccc', borderRadius: '5px', padding: '4px', fontSize: '0.8rem', textAlign: 'center', fontFamily: 'Cairo, sans-serif', background: 'white', fontWeight: 700 }} value={layers} onChange={e => onLayers(e.target.value)}><option value="1">طبقة</option><option value="2">طبقتين</option></select>
                                                                                                                                                                                                                                                                                                              </div>
                                                                                                                                                                                                                                                                                                                  </div>
                                                                                                                                                                                                                                                                                                                    );
                                                                                                                                                                                                                                                                                                                    };

                                                                                                                                                                                                                                                                                                                    return (
                                                                                                                                                                                                                                                                                                                      <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                                                                                                                                                                                                                                                                                                                          <div className="model-card" style={{ border: '1px solid #ddd', borderRadius: '12px', overflow: 'hidden', background: 'white' }}>
                                                                                                                                                                                                                                                                                                                                <div className="model-head" onClick={toggle} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '10px 12px', background: '#f8fafc', cursor: 'pointer' }}>
                                                                                                                                                                                                                                                                                                                                        <span style={{ fontWeight: 700, color: '#003366', fontSize: '0.9rem' }}>📋 بيانات الخزان</span>
                                                                                                                                                                                                                                                                                                                                                <span>{open ? '▲' : '▼'}</span>
                                                                                                                                                                                                                                                                                                                                                      </div>
                                                                                                                                                                                                                                                                                                                                                            {open && (
                                                                                                                                                                                                                                                                                                                                                                    <div className="model-body" style={{ padding: '10px 12px' }}>
                                                                                                                                                                                                                                                                                                                                                                              <SectionTitle>الأبعاد (م)</SectionTitle>
                                                                                                                                                                                                                                                                                                                                                                                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '8px', marginBottom: '12px' }}>
                                                                                                                                                                                                                                                                                                                                                                                                    <Num id="tank-l" go="tank-w" label="الطول" value={data.length} set={(v: string) => update('length', v)} unit="م" />
                                                                                                                                                                                                                                                                                                                                                                                                                <Num id="tank-w" go="tank-h" label="العرض" value={data.width} set={(v: string) => update('width', v)} unit="م" />
                                                                                                                                                                                                                                                                                                                                                                                                                            <Num id="tank-h" go="tank-ft" label="الارتفاع" value={data.height} set={(v: string) => update('height', v)} unit="م" />
                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                <SectionTitle>السماكة (سم)</SectionTitle>
                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '8px', marginBottom: '12px' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <Num id="tank-ft" go="tank-wt" label="الأرضية" value={data.floorThick} set={(v: string) => update('floorThick', v)} unit="سم" />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <Num id="tank-wt" go="tank-rt" label="الجدران" value={data.wallThick} set={(v: string) => update('wallThick', v)} unit="سم" />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <Num id="tank-rt" go="floor-long" label="السقف" value={data.roofThick} set={(v: string) => update('roofThick', v)} unit="سم" />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <SectionTitle>تسليح أرضية الخزان</SectionTitle>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <SteelRow id="floor-long" go="floor-dia" label="طولي / متر" count={data.floorLongCount} dia={data.floorLongDia} layers={data.floorLongLayers} onCount={(v: string) => update('floorLongCount', v)} onDia={(v: number) => update('floorLongDia', v)} onLayers={(v: string) => update('floorLongLayers', v)} />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <SteelRow id="floor-cross" go="floor-cross-dia" label="عرضي / متر" count={data.floorCrossCount} dia={data.floorCrossDia} layers={data.floorCrossLayers} onCount={(v: string) => update('floorCrossCount', v)} onDia={(v: number) => update('floorCrossDia', v)} onLayers={(v: string) => update('floorCrossLayers', v)} />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <SectionTitle>تسليح جدران الخزان</SectionTitle>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <SteelRow id="wall-v" go="wall-v-dia" label="رأسي / متر" count={data.wallVCount} dia={data.wallVDia} layers={data.wallVLayers} onCount={(v: string) => update('wallVCount', v)} onDia={(v: number) => update('wallVDia', v)} onLayers={(v: string) => update('wallVLayers', v)} />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <SteelRow id="wall-h" go="wall-h-dia" label="أفقي / متر" count={data.wallHCount} dia={data.wallHDia} layers={data.wallHLayers} onCount={(v: string) => update('wallHCount', v)} onDia={(v: number) => update('wallHDia', v)} onLayers={(v: string) => update('wallHLayers', v)} />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <SectionTitle>تسليح سقف الخزان</SectionTitle>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <SteelRow id="roof-long" go="roof-long-dia" label="طولي / متر" count={data.roofLongCount} dia={data.roofLongDia} layers={data.roofLongLayers} onCount={(v: string) => update('roofLongCount', v)} onDia={(v: number) => update('roofLongDia', v)} onLayers={(v: string) => update('roofLongLayers', v)} />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <SteelRow id="roof-cross" label="عرضي / متر" count={data.roofCrossCount} dia={data.roofCrossDia} layers={data.roofCrossLayers} onCount={(v: string) => update('roofCrossCount', v)} onDia={(v: number) => update('roofCrossDia', v)} onLayers={(v: string) => update('roofCrossLayers', v)} />

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div className="no-print" style={{ display: 'flex', gap: '8px', marginTop: '12px' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <button onClick={reset} style={{ flex: 1, padding: '10px', border: 'none', borderRadius: '10px', background: '#dc3545', color: 'white', fontWeight: 700, fontSize: '0.8rem', cursor: 'pointer', fontFamily: 'Cairo, sans-serif' }}>تفريغ المدخلات</button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <button onClick={calculate} style={{ flex: 1, padding: '10px', border: 'none', borderRadius: '10px', background: '#00509e', color: 'white', fontWeight: 700, fontSize: '0.8rem', cursor: 'pointer', fontFamily: 'Cairo, sans-serif' }}>حساب الكميات</button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>      {/* النتائج */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div style={{ pageBreakBefore: 'always' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <SectionTitle>النتائج</SectionTitle>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div className="results-grid" style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div className="result-tile" style={{ border: '1px solid #28a745', borderRadius: '10px', padding: '10px 8px', textAlign: 'center', background: '#fafffe' }}><span style={{ fontSize: '0.55rem', color: '#555', fontWeight: 700 }}>سعة الخزان</span><strong style={{ fontSize: '1rem', fontWeight: 700, color: '#28a745', display: 'block' }}>{fmtNum(capacity)} م³</strong></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div className="result-tile" style={{ border: '1px solid #28a745', borderRadius: '10px', padding: '10px 8px', textAlign: 'center', background: '#fafffe' }}><span style={{ fontSize: '0.55rem', color: '#555', fontWeight: 700 }}>خرسانة الأرضية</span><strong style={{ fontSize: '1rem', fontWeight: 700, color: '#28a745', display: 'block' }}>{fmtNum(floorConcrete)} م³</strong></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <div className="result-tile" style={{ border: '1px solid #28a745', borderRadius: '10px', padding: '10px 8px', textAlign: 'center', background: '#fafffe' }}><span style={{ fontSize: '0.55rem', color: '#555', fontWeight: 700 }}>خرسانة الجدران</span><strong style={{ fontSize: '1rem', fontWeight: 700, color: '#28a745', display: 'block' }}>{fmtNum(wallConcrete)} م³</strong></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div className="result-tile" style={{ border: '1px solid #28a745', borderRadius: '10px', padding: '10px 8px', textAlign: 'center', background: '#fafffe' }}><span style={{ fontSize: '0.55rem', color: '#555', fontWeight: 700 }}>خرسانة السقف</span><strong style={{ fontSize: '1rem', fontWeight: 700, color: '#28a745', display: 'block' }}>{fmtNum(roofConcrete)} م³</strong></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div className="result-tile" style={{ border: '1px solid #28a745', borderRadius: '10px', padding: '10px 8px', textAlign: 'center', background: '#fafffe' }}><span style={{ fontSize: '0.55rem', color: '#555', fontWeight: 700 }}>إجمالي الخرسانة</span><strong style={{ fontSize: '1rem', fontWeight: 700, color: '#28a745', display: 'block' }}>{fmtNum(totalConcrete)} م³</strong></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div className="result-tile" style={{ border: '1px solid #28a745', borderRadius: '10px', padding: '10px 8px', textAlign: 'center', background: '#fafffe' }}><span style={{ fontSize: '0.55rem', color: '#555', fontWeight: 700 }}>إجمالي الحديد</span><strong style={{ fontSize: '1rem', fontWeight: 700, color: '#28a745', display: 'block' }}>{fmtNum(totalSteelTon)} طن</strong></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <SectionTitle>جدول الحديد</SectionTitle>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div className="table-wrap" style={{ marginTop: '15px', marginBottom: '15px' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.7rem' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <thead>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <tr style={{ background: '#003366', color: 'white' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <th style={{ padding: '8px 5px', border: '1px solid #003366' }}>البند</th>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <th style={{ padding: '8px 5px', border: '1px solid #003366' }}>القطر</th>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <th style={{ padding: '8px 5px', border: '1px solid #003366' }}>عدد الأسياخ</th>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <th style={{ padding: '8px 5px', border: '1px solid #003366' }}>الوزن طن</th>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </tr>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </thead>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <tbody>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  {items.map((item, idx) => (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <tr key={idx} style={{ background: idx % 2 === 0 ? 'white' : '#f8fafc' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <td style={{ padding: '6px 5px', border: '1px solid #ccc', textAlign: 'center' }}>{item.label}</td>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <td style={{ padding: '6px 5px', border: '1px solid #ccc', textAlign: 'center' }}>{item.d} مم</td>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <td style={{ padding: '6px 5px', border: '1px solid #ccc', textAlign: 'center' }}>{item.bars}</td>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <td style={{ padding: '6px 5px', border: '1px solid #ccc', textAlign: 'center' }}>{fmtNum(toTons(item.bars, item.d))}</td>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </tr>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        ))}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      {/* صفوف الأقطار المجمعة */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    {(() => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const summaryByDia: Record<number, number> = {};
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    items.forEach(item => { summaryByDia[item.d] = (summaryByDia[item.d] || 0) + item.bars; });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    return Object.entries(summaryByDia).sort(([a], [b]) => +a - +b).map(([dia, bars]) => (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <tr key={`sum-${dia}`} style={{ background: '#e8f0fe', fontWeight: 700 }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <td style={{ padding: '6px 5px', border: '1px solid #ccc', textAlign: 'center' }}>إجمالي</td>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <td style={{ padding: '6px 5px', border: '1px solid #ccc', textAlign: 'center' }}>{dia} مم</td>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <td style={{ padding: '6px 5px', border: '1px solid #ccc', textAlign: 'center' }}>{bars}</td>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <td style={{ padding: '6px 5px', border: '1px solid #ccc', textAlign: 'center' }}>{fmtNum(toTons(bars, Number(dia)))}</td>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </tr>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        ));
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      })()}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <tr className="total-row" style={{ background: '#003366', color: '#FFD700', fontWeight: 700 }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <td style={{ padding: '8px 5px', border: '1px solid #003366', textAlign: 'center' }}>الإجمالي الكلي</td>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <td style={{ padding: '8px 5px', border: '1px solid #003366', textAlign: 'center' }}>-</td>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <td style={{ padding: '8px 5px', border: '1px solid #003366', textAlign: 'center' }}>-</td>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <td style={{ padding: '8px 5px', border: '1px solid #003366', textAlign: 'center' }}>{fmtNum(totalSteelTon)}</td>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </tr>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </tbody>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </table>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div className="no-print" style={{ display: 'flex', gap: '6px', padding: '12px 15px', background: 'white', borderTop: '1px solid #eee', marginTop: 'auto' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <button style={{ flex: 1, padding: '10px', border: 'none', borderRadius: '10px', background: '#28a745', color: 'white', fontWeight: 700, fontSize: '0.8rem', cursor: 'pointer', fontFamily: 'Cairo, sans-serif' }} onClick={() => window.print()}>🖨️ طباعة PDF</button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                };

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                export default Tank;